// Basic usage
TArray<FString> Names;
Names.Add(TEXT("Alice"));
Names.Add(TEXT("Bob"));
Names.AddUnique(TEXT("Alice")); // Won't add duplicate

// Iteration
for (const FString& Name : Names) {
    UE_LOG(LogTemp, Log, TEXT("%s"), *Name);
}

// Find
int32 Index = Names.Find(TEXT("Bob")); // Returns 1
if (Index != INDEX_NONE) { /* found */ }

// Find with predicate
FString* Found = Names.FindByPredicate([](const FString& S) {
    return S.StartsWith(TEXT("A"));
});
if (Found) { /* *Found == "Alice" */ }

// Remove while iterating (backward)
for (int32 i = Names.Num() - 1; i >= 0; i--) {
    if (Names[i].Len() < 4) Names.RemoveAt(i);
}

// Sort
TArray<int32> Scores = {50, 10, 90, 30};
Scores.Sort(); // Ascending
Scores.Sort([](int32 A, int32 B) { return A > B; }); // Descending

// UPROPERTY
UPROPERTY(EditAnywhere, BlueprintReadWrite)
TArray<TSubclassOf<AWeapon>> WeaponClasses;

// Inventory: item name -> count
TMap<FName, int32> Inventory;
Inventory.Add(TEXT("HealthPotion"), 5);
Inventory.Add(TEXT("ManaPotion"), 3);

// Safe lookup
if (int32* Count = Inventory.Find(TEXT("HealthPotion"))) {
    UE_LOG(LogTemp, Log, TEXT("Has %d health potions"), *Count);
    (*Count)--;  // Consume one
}

// FindOrAdd (insert default 0 if not found)
int32& SwordCount = Inventory.FindOrAdd(TEXT("Sword"));
SwordCount += 1;

// Iteration
for (auto& Pair : Inventory) {
    UE_LOG(LogTemp, Log, TEXT("%s: %d"), *Pair.Key.ToString(), Pair.Value);
}

// UPROPERTY
UPROPERTY(EditAnywhere, BlueprintReadWrite)
TMap<FName, float> DamageMultipliers;

// Remove
Inventory.Remove(TEXT("ManaPotion"));

// Track actors in a trigger zone
TSet<AActor*> ActorsInZone;

void AMyTrigger::OnOverlapBegin(AActor* Actor) {
    ActorsInZone.Add(Actor);
}

void AMyTrigger::OnOverlapEnd(AActor* Actor) {
    ActorsInZone.Remove(Actor);
}

bool AMyTrigger::IsActorInZone(AActor* Actor) const {
    return ActorsInZone.Contains(Actor);
}

