// Set operations
TSet<FName> SetA = {TEXT("A"), TEXT("B"), TEXT("C")};
TSet<FName> SetB = {TEXT("B"), TEXT("C"), TEXT("D")};
TSet<FName> Both = SetA.Intersect(SetB);  // {B, C}
TSet<FName> All = SetA.Union(SetB);       // {A, B, C, D}
TSet<FName> OnlyA = SetA.Difference(SetB); // {A}
